#include<bits/stdc++.h>
using namespace std;
int main() {
	int a,b,num1=0,num2=0;float ping1=0,ping2=0;
	cin>>a>>b;
	for(int i=1;i<=a;i++){
		if(i%b==0){
			num1+=i;
			ping1+=1;
		}else{
			num2+=i;
			ping2+=1;
		}
	}ping1=num1/ping1;	
	ping2=num2/ping2;
	cout<<fixed<<setprecision(1)<<ping1<<" "<<fixed<<setprecision(1)<<ping2;			
}
